import React,{useEffect,useRef} from 'react';
import {Animated,StyleSheet,View} from 'react-native';
export default function AtomView({number}){const spin=useRef(new Animated.Value(0)).current;useEffect(()=>{spin.setValue(0);Animated.loop(Animated.timing(spin,{toValue:1,duration:6500,useNativeDriver:true})).start();},[number,spin]);const rot=spin.interpolate({inputRange:[0,1],outputRange:['0deg','360deg']});const count=Math.min(18,Math.max(2,number));return <View style={s.stage}><View style={s.nucleus}>{Array.from({length:Math.min(20,number+2)},(_,i)=><View key={i} style={[s.dot,{backgroundColor:i%2?'#6a7dff':'#ff466f'}]}/>)}</View>{[0,1,2].map((ring)=><Animated.View key={ring} style={[s.orbit,{width:130+ring*46,height:48+ring*20,transform:[{rotate:`${ring*58}deg`},{rotateZ:rot}]}]}>{Array.from({length:Math.min(6,Math.ceil(count/3))},(_,i)=><View key={i} style={[s.electron,{transform:[{rotate:`${i*60}deg`},{translateX:(130+ring*46)/2}]}]}/>)}</Animated.View>)}</View>}
const s=StyleSheet.create({stage:{width:280,height:210,alignItems:'center',justifyContent:'center'},nucleus:{width:58,height:58,borderRadius:29,flexDirection:'row',flexWrap:'wrap',alignItems:'center',justifyContent:'center',backgroundColor:'#101a35',zIndex:5},dot:{width:10,height:10,borderRadius:5,margin:-1},orbit:{position:'absolute',borderWidth:1,borderColor:'#64cfff88',borderRadius:999},electron:{position:'absolute',left:'50%',top:'50%',width:8,height:8,borderRadius:4,backgroundColor:'#7de6ff'}});
